import json
# Accessing stored results
reviews = var_call_w0nT65dVo5XCbvip6ZQFwNXG
businesses = var_call_OqtEqXzXBFnCN3Qrve0fbrxy

# Build set of business ids that had reviews in 2018
business_refs = {r['business_ref'] for r in reviews}
# Convert to business_id form
business_ids_from_reviews = {br.replace('businessref_', 'businessid_') for br in business_refs}

# Build mapping from business_id to attributes
biz_attr = {b['business_id']: b.get('attributes') for b in businesses}

count = 0
matched_businesses = []
for bid in business_ids_from_reviews:
    attrs = biz_attr.get(bid)
    has_parking = False
    if attrs:
        # Check BikeParking
        bike = attrs.get('BikeParking')
        if isinstance(bike, bool):
            if bike:
                has_parking = True
        elif isinstance(bike, str):
            if bike.lower().strip() == 'true':
                has_parking = True
        # Check BusinessParking
        bp = attrs.get('BusinessParking')
        if not has_parking and bp is not None:
            # If it's a dict-like string, check for True
            if isinstance(bp, dict):
                if any(v is True or (isinstance(v, str) and v.lower().strip() == 'true') for v in bp.values()):
                    has_parking = True
            else:
                bp_str = str(bp)
                # Consider 'None' as no parking
                if 'true' in bp_str.lower():
                    has_parking = True
    if has_parking:
        count += 1
        matched_businesses.append(bid)

result = {"count": count, "businesses_with_parking": sorted(list(matched_businesses))}

print("__RESULT__:")
print(json.dumps(result))

